using Common.Geometry;
using Common;
using Script;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System;
using System.Linq;

namespace Plugin.ScriptCSharp
{
    /// <summary>
    /// 脚本功能：写自动采集相机标定点坐标
    /// 根据采集起点生成9点标定路径，全部使用脉冲计算，最后返回起点
    /// 同时生成九点标定坐标字典（单位mm），用于相机标定
    /// </summary>
    public class ScriptWriteAutoCollectCalibPoint : IScript
    {
        public ConcurrentDictionary<string, object> Execute(ConcurrentDictionary<string, object> parameters)
        {
            // 初始化返回结果字典
            ConcurrentDictionary<string, object> result = new ConcurrentDictionary<string, object>();

            // ===================== 读取参数（全部脉冲/直接使用）=====================
            // 采集起点（直接使用脉冲值）
            int startXPulse = (int)parameters["写自动采集相机标定点坐标.采集起点X（脉冲）"];
            int startYPulse = (int)parameters["写自动采集相机标定点坐标.采集起点Y（脉冲）"];

            // 步长（mm）
            double stepXmm = (double)parameters["写自动采集相机标定点坐标.X方向步长（mm）"];
            double stepYmm = (double)parameters["写自动采集相机标定点坐标.Y方向步长（mm）"];

            // PLC当量（mm/脉冲）
            double plcScaleX = (double)parameters["全局.PLC_X当量值"];
            double plcScaleY = (double)parameters["全局.PLC_X当量值"];

            // 状态变量
            short i = 0;
            bool b = false;

            // ===================== 脚本执行前：清空九点标定坐标字典 =====================
            // 新建空字典，用于后续赋值
            Dictionary<string, Point> calibDict = new Dictionary<string, Point>();

            // ===================== 参数校验 =====================
            if (startXPulse != 0 && startYPulse != 0 && stepXmm > 0 && stepYmm > 0 && plcScaleX > 0 && plcScaleY > 0)
            {
                // ===================== 核心：步长转脉冲（mm × 当量 = 脉冲）=====================
                int stepX = (int)(stepXmm * plcScaleX);
                int stepY = (int)(stepYmm * plcScaleY);

                // ===================== 9点路径 + 返回起点（全部脉冲计算）=====================
                List<int> xList = new List<int>();
                List<int> yList = new List<int>();

                // 1 起点
                xList.Add(startXPulse);
                yList.Add(startYPulse);
                calibDict.Add("1", new Point(startXPulse / plcScaleX, startYPulse / plcScaleY));

                // 2 X+
                xList.Add(startXPulse + stepX);
                yList.Add(startYPulse);
                calibDict.Add("2", new Point((startXPulse + stepX) / plcScaleX, startYPulse / plcScaleY));

                // 3 Y+
                xList.Add(startXPulse + stepX);
                yList.Add(startYPulse + stepY);
                calibDict.Add("3", new Point((startXPulse + stepX) / plcScaleX, (startYPulse + stepY) / plcScaleY));

                // 4 X-
                xList.Add(startXPulse);
                yList.Add(startYPulse + stepY);
                calibDict.Add("4", new Point(startXPulse / plcScaleX, (startYPulse + stepY) / plcScaleY));

                // 5 X-
                xList.Add(startXPulse - stepX);
                yList.Add(startYPulse + stepY);
                calibDict.Add("5", new Point((startXPulse - stepX) / plcScaleX, (startYPulse + stepY) / plcScaleY));

                // 6 Y-
                xList.Add(startXPulse - stepX);
                yList.Add(startYPulse);
                calibDict.Add("6", new Point((startXPulse - stepX) / plcScaleX, startYPulse / plcScaleY));

                // 7 Y-
                xList.Add(startXPulse - stepX);
                yList.Add(startYPulse - stepY);
                calibDict.Add("7", new Point((startXPulse - stepX) / plcScaleX, (startYPulse - stepY) / plcScaleY));

                // 8 X+
                xList.Add(startXPulse);
                yList.Add(startYPulse - stepY);
                calibDict.Add("8", new Point(startXPulse / plcScaleX, (startYPulse - stepY) / plcScaleY));

                // 9 X+
                xList.Add(startXPulse + stepX);
                yList.Add(startYPulse - stepY);
                calibDict.Add("9", new Point((startXPulse + stepX) / plcScaleX, (startYPulse - stepY) / plcScaleY));

                //// 回到起点（闭环）
                //xList.Add(startXPulse);
                //yList.Add(startYPulse);
                //calibDict.Add("10", new Point(startXPulse / plcScaleX, startYPulse / plcScaleY));

                // ===================== 输出结果 =====================
                result.TryAdd("写自动采集相机标定点坐标.路径X组", xList);
                result.TryAdd("写自动采集相机标定点坐标.路径Y组", yList);
                result.TryAdd("全局.九点标定坐标字典", calibDict); // 新增：单位mm的坐标字典
                b = true;
            }
            else
            {
                string retMsg = parameters.ConvertToString();
                result.TryAdd("返回消息", $"参数错误：采集起点/步长/当量异常 {retMsg}");
                // 即使参数错误，也输出空字典，保证界面变量不报错
                result.TryAdd("全局.九点标定坐标字典", calibDict);
            }

            // 状态输出
            i = (short)(b ? 1 : 2);
            result.TryAdd("写自动采集相机标定点坐标.PLC写入结果", b);
            result.TryAdd("任务结果状态", i);
            result.TryAdd("运行结果", b);

            return result;
        }
    }
}
